// Build standup summary
const completed = $('Fetch Completed Tasks').first().json || [];
const open      = $('Fetch Open Tasks').first().json || [];

const kw = Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 604800000);
const today = new Date().toLocaleDateString('de-DE', { weekday: 'long', day: '2-digit', month: 'long' });

// Group completed by intern
const byIntern = {};
for (const t of completed) {
  const key = t.assigned_to_email;
  if (!byIntern[key]) byIntern[key] = { done: [], open: [] };
  byIntern[key].done.push(t);
}
for (const t of open) {
  const key = t.assigned_to_email;
  if (!byIntern[key]) byIntern[key] = { done: [], open: [] };
  byIntern[key].open.push(t);
}

const overdue = open.filter(t => t.due_date && t.due_date < new Date().toISOString().split('T')[0]);

const content = `# Intern Standup — KW${kw} | ${today}\n\n` +
  `**Uhrzeit:** 11:00 | **Dauer:** 15–20 Min\n\n` +
  `---\n\n` +
  `## ✅ Letzte Woche abgeschlossen (${completed.length} Tasks)\n\n` +
  Object.entries(byIntern).map(([email, data]) => {
    const name = email.split('@')[0];
    return `**${name}:** ${data.done.map(t => t.title).join(', ') || '—'}`;
  }).join('\n') +
  `\n\n---\n\n` +
  `## 📋 Diese Woche offen (${open.length} Tasks)\n\n` +
  Object.entries(byIntern).map(([email, data]) => {
    const name = email.split('@')[0];
    if (!data.open.length) return null;
    return `**${name}:**\n` + data.open.map(t => `  - [ ] ${t.title} _(${t.brand || 'Cross-brand'}, P${t.priority})_`).join('\n');
  }).filter(Boolean).join('\n\n') +
  (overdue.length ? `\n\n---\n\n## ⚠️ Überfällig (${overdue.length})\n\n` +
    overdue.map(t => `- ${t.title} — ${t.assigned_to_email.split('@')[0]} (seit ${t.due_date})`).join('\n') : '') +
  `\n\n---\n\n## 📝 Standup Notizen\n\n> _Luis füllt während des Meetings aus_\n\n` +
  `**Blockers:**\n\n**Feedback letzte Woche:**\n\n**Nächste Prioritäten:**`;

return [{ json: { content, week: kw, date: today } }];
